/*
 * doname.c - basic procedure. RECURSIVE.
 *
 * p->done = 0   don't know what to do yet
 * p->done = 1   file in process of being updated
 * p->done = 2   file already exists in current state
 * p->done = 3   file make failed
 */

doname(p, reclevel, tval) {
    if (p->done > 0) {            /* memoization */
        *tval = p->modtime;
        return(p->done == 3);
    }
    ptime = exists(p->namep);      /* target mtime */
    p->done = 1;                    /* mark in-progress, detect loops */

    for(lp = p->linep; lp; lp = lp->nxtlineblock) {
        for(q = lp->depp; q; q = q->nxtdepblock) {
            errstat += doname(q->depname, reclevel+1, &td1);  /* recurse */
            if (ptime < td1)
                qchain = appendq(qchain, q->depname->namep);
            if (td1 > td) td = td1;
        }
    }
    if (errstat==0 && (ptime < tdep || (ptime==0 && tdep==0))) {
        setvar("@", p->namep);
        setvar("?", mkqlist(qchain));
        if (explcom) errstat += docom(explcom);
        else if (implcom) errstat += docom(implcom);
    }
    p->done = (errstat ? 3 : 2);
}

TIMETYPE exists(name) char *name; {
    if (stat(name, &statb) < 0)
        return(0);                  /* doesn't exist */
    return(statb.st_mtime);
}

