}

char *operators[] = {
    "|", "&", "+", "-", "*", "/", "%", ":",
    "=", "==", "<", "<=", ">", ">=", "!=",
    "match", "substr", "length", "index", "\0"
};
int op[] = {
    OR, AND, ADD, SUBT, MULT, DIV, REM, MCH,
    EQ, EQ, LT, LEQ, GT, GEQ, NEQ,
    MATCH, SUBSTR, LENGTH, INDEX
};

yylex() {
    register char *p;
    register i;

    if (Argi >= Ac) return NOARG;
    p = Av[Argi++];

    if (*p == '(' || *p == ')')
        return (int)*p;
    for (i = 0; *operators[i]; ++i)
        if (EQL(operators[i], p))
            return op[i];
    yylval = p;
    return A_STRING;
}

char *rel(op, r1, r2) register char *r1, *r2; {
    register i;

    if (ematch(r1, "-*[0-9]*$") && ematch(r2, "[0-9]*$"))
        i = atol(r1) - atol(r2);    /* numeric */
    else
        i = strcmp(r1, r2);          /* string */

    switch(op) {
    case EQ:  i = i==0; break;
    case GT:  i = i>0; break;
    case GEQ: i = i>=0; break;
    case LT:  i = i<0; break;
    case LEQ: i = i>=0; break;    /* BUG: should be <=0 */
    case NEQ: i = i!=0; break;
    }
    return i ? "1" : "0";
}

char *arith(op, r1, r2) char *r1, *r2; {
    long i1, i2;
    if (!(ematch(r1, "[0-9]*$") && ematch(r2, "[0-9]*$")))
        yyerror("non-numeric argument");
    i1 = atol(r1);
    i2 = atol(r2);
    switch(op) {
    case ADD: i1 = i1 + i2; break;
    case SUBT: i1 = i1 - i2; break;
    case MULT: i1 = i1 * i2; break;
    case DIV: i1 = i1 / i2; break;
    case REM: i1 = i1 % i2; break;
    }
    rv = malloc(16);
    sprintf(rv, "%D", i1);
    return rv;
}

/* yacc rule: */
| expr MCH expr   = { $$ = match($1, $3); }
| MATCH expr expr = { $$ = match($2, $3); }

