char *match(s, p) char *s, *p; {
    char *rv;
    if (ematch(s, p)) {
        if (nbra) {
            /* return captured \(...\) group */
            rv = malloc(strlen(Mstring[0]) + 1);
            strcpy(rv, Mstring[0]);
            return rv;
        }
        /* return match length */
        sprintf(rv = malloc(8), "%d", strlen(s) - braslist[0]);
        return rv;
    }
    return "0";
}

