dodef(p) char *p; {
    char *formal[MAXFRM];     /* formal[n] = name of nth formal */
    char formtxt[BUFSIZ];

    np = slookup(pin, p, 1);   /* lookup or create */

    /* update macbit (superimposed code) */
    b = 1; cf = pin;
    while (cf < p) {
        c = *cf++; xmac1(c, b, |=);
        b = (b+b) & 0xFF;
    }

    params = 0;
    if (*pin == '(') {         /* function-like macro */
        cf = formtxt; pf = formal;
        for (;;) {
            p = skipbl(p);
            if (*pin == ')') break;
            if (*pin == ',') continue;
            *pf++ = cf;
            while (pin < p) *cf++ = *pin++;
            *cf++ = '\0';
            ++params;
        }
    }

    /* accumulate body, mark formals with WARN bytes */
    for (;;) {
        if (*pin == '\n') break;
        if (params && (toktyp+COFF)[*pin] == IDENT) {
            for (qf=pf; --qf >= formal; ) {
                if (equfrm(*qf, pin, p)) {
                    *psav++ = qf-formal+1;   /* parameter index */
                    *psav++ = WARN;          /* marker */
                    pin = p; break;
                }
            }
        }
        while (pin < p) *psav++ = *pin++;
    }
    *psav++ = params;
    *psav++ = '\0';
    np->value = psav-1;
}

doincl(p) register char *p; {
    extern char *Inclist[];     /* search path array */
    register char *fname;

    p = skipbl(p);
    if (*inp == '"') {            /* "filename" - user header */
        bp = ++inp;
        while (*inp != '"') ++inp;
    } else if (*inp == '<') {     /* <filename> - system header */
        bp = ++inp;
        while (*inp != '>') ++inp;
    }

    /* try current dir first for "..." */
    if (*pin == '"') {
        sprintf(fname, "%s", bp_copy);
        if ((fno = open(fname, 0)) >= 0) goto found;
    }

    /* try each directory in Inclist (search path) */
    for (incflno=0; incflno<MAXINC && Inclist[incflno]; ++incflno) {
        sprintf(fname, "%s/%s", Inclist[incflno], bp_copy);
        if ((fno = open(fname, 0)) >= 0) goto found;
    }

    pperror("can't find include file %s", bp_copy);
    return(p);

found:
    ++ifno;
    incfile[ifno] = fno;
    lineno[ifno] = 1;
}

