offset(s) register char *s; {
    if (*s == '+') s++;
    if (*s == 'x') { s++; base = 16; }
    else if (*s == '0' && s[1] == 'x') { s += 2; base = 16; }
    else if (*s == '0') base = 8;
    p = s;
    while (*p) {
        if (*p++ == '.') base = 10;     /* trailing dot */
    }
    for (a=0; *s; s++) {
        d = *s;
        if (d >= '0' && d <= '9')
            a = a*base + d - '0';
        else if (d >= 'a' && d <= 'f' && base == 16)
            a = a*base + d + 10 - 'a';
        else break;
    }
    if (*s == '.') s++;
    if (*s == 'b' || *s == 'B') a *= 512;    /* block units */
