/*    diff - differential file comparison
*
*    Uses an algorithm due to Harold Stone, which finds
*    a pair of longest identical subsequences in the two files.
*    The major goal is to generate the match vector J.
*    J[i] is the index of the line in file1 corresponding
*    to line i file0. J[i] = 0 if there is no such line.
*/

stone(a, n, b, c) {
    int *a, *b, *c;
    int k = 0;
    c[0] = newcand(0, 0, 0);
    for (i=1; i<=n; i++) {        /* each line in file0 */
        j = a[i];                  /* equivalence class */
        if (j == 0) continue;
        y = -b[j];                 /* first member */
        oldl = 0; oldc = c[0];
        do {
            if (y <= clist[oldc].y) continue;
            l = search(c, k, y);    /* binary search */
            if (l <= k) {
                if (clist[c[l]].y <= y) continue;
                tc = c[l];
                c[l] = newcand(i, y, oldc);
                oldc = tc; oldl = l;
            } else {
                c[l] = newcand(i, y, oldc);
                k++; break;
            }
        } while ((y = b[++j]) > 0);
    }
    return(k);
}

