readin(name, dd) char *name; struct diff *dd; {
    for (i=0; getchange(fp[0]); i++) {
        a = b = number(&p);
        if (*p == ',') { p++; b = number(&p); }
        kind = *p++;       /* 'a', 'd', or 'c' */
        c = d = number(&p);
        if (*p == ',') { p++; d = number(&p); }
        if (kind == 'a') a++;
        if (kind == 'd') c++;
        b++; d++;          /* exclusive 'to' */
        dd[i].old.from = a;
        dd[i].old.to = b;
        dd[i].new.from = c;
        dd[i].new.to = d;
    }
}

merge(m1, m2) {
    d1 = d13; d2 = d23;
    for (; (t1 = d1 < d13+m1) | (t2 = d2 < d23+m2); ) {

        /* Case 1: only f1 changed */
        if (!t2 || t1 && d1->new.to < d2->new.from) {
            separate("1");
            change(1, &d1->old, 0);
            keep(2, &d1->old, &d1->new);
            change(3, &d1->new, 0);
            d1++; continue;
        }

        /* Case 2: only f2 changed */
        if (!t1 || t2 && d2->new.to < d1->new.from) {
            separate("2");
            keep(1, &d2->old, &d2->new);
            change(2, &d2->old, 0);
            change(3, &d2->new, 0);
            d2++; continue;
        }

        /* Cases 3,4: merge overlapping changes within same file */

        /* Case 5: both changed same range */
        if (d1->new.from == d2->new.from &&
            d1->new.to   == d2->new.to) {
            dup = duplicate(&d1->old, &d2->old);
            separate(dup ? "3" : "");      /* "" = CONFLICT */
            change(1, &d1->old, dup);
            change(2, &d2->old, 0);
            change(3, &d3->new, 0);
            d1++; d2++; continue;
        }

        /* Overlap: extend ranges to coincide, retry */
        if (d1->new.from < d2->new.from) {
            d2->old.from -= d2->new.from - d1->new.from;
            d2->new.from = d1->new.from;
        }
        /* ... similar for other end ... */
    }
}

separate(s) char *s; {
