}

change(i, rold, dup) struct range *rold; {
    printf("%d:", i);
    last[i] = rold->to;
    prange(rold);
    if (dup) return;
    i--;
    skip(i, rold->from, (char *)0);
    skip(i, rold->to, "  ");
