prange(rold) struct range *rold; {
    if (rold->to <= rold->from)
        printf("%da\n", rold->from-1);    /* append */
    else {
        printf("%d", rold->from);
        if (rold->to > rold->from+1)
            printf(",%d", rold->to-1);
        printf("c\n");                     /* change */
    }
}

