selunit() {   /* pick the next lesson to match the student's ability */
	while (fgets(zb,200,f)) if (strcmp(zb,"#next")==0) break;   /* the script's #next block */
	for(i=0; fgets(s,50,f); i++) sscanf(s,"%s %d", posslev[i], &diff[i]);  /* candidates + difficulty */
	n = grand()%i;                          /* from a random start */
	for(k=0; k<i; k++) { m=(n+k)%i;
		if (already(posslev[m],0)) continue;  /* skip done lessons */
		if (abs(diff[m]-speed) < abs(diff[best]-speed)) best=m;  /* difficulty nearest to speed */
	}
}

