time_t expand(t) unsigned t; {
	register time_t nt;
	nt = t & 017777;   /* low 13 bits = mantissa */
	t >>= 13;          /* high 3 bits = exponent */
	while (t != 0) { t--; nt <<= 3; }   /* shift left 3 bits per exponent unit */
	return(nt);        /* value = mantissa * 8^exponent */
}

